static const uint16_t *mote_icon_for(const char *name){
  if(!strcmp(name,"golf")) return icon_golf;
  if(!strcmp(name,"chess")) return icon_chess;
  if(!strcmp(name,"fling")) return icon_fling;
  if(!strcmp(name,"world")) return icon_world;
  if(!strcmp(name,"physics")) return icon_physics;
  if(!strcmp(name,"pool")) return icon_pool;
  if(!strcmp(name,"cluster")) return icon_cluster;
  if(!strcmp(name,"terrain")) return icon_terrain;
  if(!strcmp(name,"zelda")) return icon_zelda;
  if(!strcmp(name,"splats")) return icon_splats;
  if(!strcmp(name,"hulls")) return icon_hulls;
  if(!strcmp(name,"dominoes")) return icon_dominoes;
  if(!strcmp(name,"pickups")) return icon_pickups;
  if(!strcmp(name,"playground")) return icon_playground;
  if(!strcmp(name,"shooter")) return icon_shooter;
  if(!strcmp(name,"materials")) return icon_materials;
  if(!strcmp(name,"hello-mesh")) return icon_hello_mesh;
  if(!strcmp(name,"tiledemo")) return icon_tiledemo;
  if(!strcmp(name,"tumbler")) return icon_tumbler;
  return 0;
}
